    @Override Button btn(String t){Button b=new Button(this);b.setText(t);b.setAllCaps(false);b.setTextColor(blue);b.setTextSize(12);b.setTypeface(Typeface.DEFAULT,Typeface.BOLD);b.setMinHeight(dp(44));b.setPadding(dp(10),dp(4),dp(10),dp(4));b.setBackground(bgRound(Color.rgb(232,239,250),999));b.setElevation(dp(2));return b;}
    @Override LinearLayout card(){LinearLayout c=new LinearLayout(this);c.setOrientation(LinearLayout.VERTICAL);c.setPadding(dp(18),dp(18),dp(18),dp(18));c.setBackground(bgStroke(white,28,Color.rgb(220,227,236)));c.setElevation(dp(8));LinearLayout.LayoutParams lp=new LinearLayout.LayoutParams(-1,-2);lp.setMargins(dp(16),dp(10),dp(16),dp(10));c.setLayoutParams(lp);return c;}
